import { TypeQuizQuestion } from "./quiz-types";
export const newQType3: TypeQuizQuestion[] = [
  // ── DIFFICULTY 1 (20 questions) ──
  { id: 651, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Real-Life Scenarios", question: "A Type 3 walks into a networking event. What is their first instinct?", options: [{ letter: "A", text: "Find a quiet corner to observe the room" }, { letter: "B", text: "Scan for the most important or influential people and position themselves accordingly" }, { letter: "C", text: "Look for someone who seems lonely and befriend them" }, { letter: "D", text: "Head straight for the food table" }], answer: "B", explanation: "Threes automatically assess the social landscape for strategic positioning. They instinctively identify who matters, who can advance their goals, and how to present themselves for maximum impact." },
  { id: 652, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Real-Life Scenarios", question: "A Type 3 finishes a major project at work. What do they do next?", options: [{ letter: "A", text: "Take a well-deserved break and celebrate" }, { letter: "B", text: "Immediately pivot to the next goal, there's no time to rest" }, { letter: "C", text: "Reflect deeply on what the project meant to them emotionally" }, { letter: "D", text: "Worry about whether anyone noticed their work" }], answer: "B", explanation: "Threes struggle to pause between achievements. Resting feels like falling behind. The treadmill of accomplishment keeps spinning because their sense of worth is tied to productivity, not being." },
  { id: 653, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Emotional Reactions", question: "When a Type 3 fails publicly, their first response is usually:", options: [{ letter: "A", text: "Deep sadness and withdrawal" }, { letter: "B", text: "Rapidly reframing the failure as a strategic pivot or learning experience" }, { letter: "C", text: "Blaming others for the failure" }, { letter: "D", text: "Accepting it with calm grace" }], answer: "B", explanation: "Threes are master spin doctors, especially with themselves. Failure threatens their core identity, so they instinctively repackage it into something that still sounds like winning: 'I didn't fail, I pivoted.'" },
  { id: 654, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Emotional Reactions", question: "How does a Type 3 typically experience sadness?", options: [{ letter: "A", text: "They feel it deeply and express it freely" }, { letter: "B", text: "They suppress it and channel the energy into productivity" }, { letter: "C", text: "They intellectualize it and analyze its causes" }, { letter: "D", text: "They project it onto others" }], answer: "B", explanation: "Threes disconnect from uncomfortable emotions by doing. Sadness feels unproductive, so they convert emotional pain into fuel for the next achievement, often not realizing they're sad until they crash." },
  { id: 655, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Type in Pop Culture", question: "Which fictional character best exemplifies Type 3 traits of image-crafting and achievement drive?", options: [{ letter: "A", text: "Don Draper from Mad Men" }, { letter: "B", text: "Samwise Gamgee from Lord of the Rings" }, { letter: "C", text: "Luna Lovegood from Harry Potter" }, { letter: "D", text: "Forrest Gump" }], answer: "A", explanation: "Don Draper is the quintessential Three: a fabricated identity, masterful self-presentation, relentless drive for success, emotional inaccessibility, and the constant gap between who he appears to be and who he actually is." },
  { id: 656, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Type in Pop Culture", question: "In the show Succession, which character most displays Type 3 patterns of shape-shifting to gain approval?", options: [{ letter: "A", text: "Roman Roy" }, { letter: "B", text: "Kendall Roy" }, { letter: "C", text: "Connor Roy" }, { letter: "D", text: "Tom Wambsgans" }], answer: "B", explanation: "Kendall constantly reinvents himself, corporate heir, hip-hop persona, activist, ruthless executive, molding his image to whatever will earn his father's approval or the world's admiration. His identity shifts with each new strategy." },
  { id: 657, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Quick Identification", question: "Which phrase is most characteristic of a Type 3?", options: [{ letter: "A", text: "I need more time to think about this" }, { letter: "B", text: "What's the most efficient path to success here?" }, { letter: "C", text: "How is everyone feeling about this?" }, { letter: "D", text: "What's the principle at stake?" }], answer: "B", explanation: "Threes think in terms of optimization and outcomes. Their attention naturally gravitates toward efficiency, results, and the fastest route to a goal, they're human GPS systems for achievement." },
  { id: 658, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Quick Identification", question: "Which behavior pattern most suggests someone is a Type 3?", options: [{ letter: "A", text: "Changing their personality and communication style depending on the audience" }, { letter: "B", text: "Maintaining the exact same persona in every situation" }, { letter: "C", text: "Withdrawing from social situations to recharge" }, { letter: "D", text: "Prioritizing deep one-on-one conversations over networking" }], answer: "A", explanation: "Threes are social chameleons. They unconsciously read what each audience values and become that person, polished executive in the boardroom, casual bro at the bar, sensitive partner at home. This isn't manipulation; it's automatic." },
  { id: 659, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Common Phrases", question: "Which internal monologue is most typical for a Type 3?", options: [{ letter: "A", text: "Am I doing the right thing morally?" }, { letter: "B", text: "How am I being perceived right now?" }, { letter: "C", text: "What do I actually need?" }, { letter: "D", text: "What's the worst that could happen?" }], answer: "B", explanation: "The Three's attention is perpetually tuned to their image. They have a running internal broadcast of how they're being seen, constantly adjusting their performance to match the desired impression." },
  { id: 660, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Common Phrases", question: "A Type 3 is most likely to describe their weekend as:", options: [{ letter: "A", text: "Peaceful and restful" }, { letter: "B", text: "Productive, listing everything they accomplished" }, { letter: "C", text: "Emotionally intense and introspective" }, { letter: "D", text: "Boring and uneventful" }], answer: "B", explanation: "Threes measure time in accomplishments. Even leisure gets repackaged as productivity: 'I ran 10K, finished a book, reorganized the garage, and cooked a new recipe.' Rest without output feels like wasted time." },
  { id: 661, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 11, track2Day: 61, category: "Childhood Patterns", question: "What childhood experience is most formative for Type 3s?", options: [{ letter: "A", text: "Being told they were loved unconditionally no matter what" }, { letter: "B", text: "Learning that love and approval came through performance, achievement, or being impressive" }, { letter: "C", text: "Being given too much freedom without structure" }, { letter: "D", text: "Being isolated from peers" }], answer: "B", explanation: "Threes learned early that their value was in what they did, not who they were. Gold stars, trophies, and parental pride for achievements taught them: 'I am loved for my accomplishments, not my being.'" },
  { id: 662, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 12, track2Day: 62, category: "Childhood Patterns", question: "As children, Type 3s often stood out because they:", options: [{ letter: "A", text: "Were the class clown" }, { letter: "B", text: "Excelled at reading the room and becoming whatever would earn the most praise" }, { letter: "C", text: "Were rebellious and oppositional" }, { letter: "D", text: "Preferred solitary creative activities" }], answer: "B", explanation: "Young Threes develop a remarkable ability to read social cues and adapt. They quickly learn which persona earns applause, star student, athlete, popular kid, and perfect that role." },
  { id: 663, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 13, track2Day: 63, category: "Communication Style", question: "How does a Type 3 typically tell a story?", options: [{ letter: "A", text: "With exhaustive detail and precision" }, { letter: "B", text: "Efficiently, highlighting their role and the successful outcome" }, { letter: "C", text: "Emotionally, focusing on how they felt" }, { letter: "D", text: "Humbly, downplaying their involvement" }], answer: "B", explanation: "Threes are natural editors of their own narratives. They trim the fat, emphasize the wins, and position themselves as the protagonist who made it happen, efficient storytelling that doubles as personal branding." },
  { id: 664, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 14, track2Day: 64, category: "Communication Style", question: "In meetings, a Type 3 is most likely to:", options: [{ letter: "A", text: "Stay quiet and take notes" }, { letter: "B", text: "Steer the conversation toward action items and deliverables" }, { letter: "C", text: "Focus on team morale and relationships" }, { letter: "D", text: "Play devil's advocate on every point" }], answer: "B", explanation: "Threes are impatient with discussion that doesn't lead to action. They want meetings to produce outcomes, timelines, and clear responsibilities, talking without doing feels wasteful to them." },
  { id: 665, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 15, track2Day: 65, category: "Real-Life Scenarios", question: "A Type 3 is scrolling social media. What are they most likely doing?", options: [{ letter: "A", text: "Mindlessly browsing memes" }, { letter: "B", text: "Curating their own profile or benchmarking themselves against peers' accomplishments" }, { letter: "C", text: "Reading long-form articles about philosophy" }, { letter: "D", text: "Checking in on friends' emotional well-being" }], answer: "B", explanation: "Social media is both a stage and a scoreboard for Threes. They craft their online image carefully while unconsciously comparing their achievements to others' highlight reels." },
  { id: 666, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 16, track2Day: 66, category: "Emotional Reactions", question: "When someone else gets a promotion the Three wanted, they feel:", options: [{ letter: "A", text: "Genuine happiness for the other person" }, { letter: "B", text: "A sharp competitive sting they quickly convert into motivation to outperform" }, { letter: "C", text: "Deep existential despair" }, { letter: "D", text: "Indifference, titles don't matter" }], answer: "B", explanation: "Threes metabolize envy into fuel. The sting of losing triggers their competitive engine: 'Watch me come back stronger.' They rarely sit with the pain, they use it." },
  { id: 667, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 17, track2Day: 67, category: "Quick Identification", question: "Which resume trait most suggests a Type 3?", options: [{ letter: "A", text: "Extensive volunteer work" }, { letter: "B", text: "A long list of quantifiable achievements and career milestones" }, { letter: "C", text: "A creative portfolio with experimental projects" }, { letter: "D", text: "One long tenure at a single company" }], answer: "B", explanation: "Threes build trophy-case resumes: numbers, rankings, promotions, and measurable wins. Each line item is carefully selected to demonstrate upward momentum and impressive outcomes." },
  { id: 668, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 18, track2Day: 68, category: "Common Phrases", question: "Which phrase reveals the Three's core relationship with time?", options: [{ letter: "A", text: "There's always tomorrow" }, { letter: "B", text: "Time is money, I can't afford to waste it" }, { letter: "C", text: "I wish I could slow down and enjoy the moment" }, { letter: "D", text: "Time doesn't really matter" }], answer: "B", explanation: "Threes experience time as a resource to be optimized. Wasted time equals wasted potential, which equals wasted identity. This creates the perpetual busyness that defines the Three lifestyle." },
  { id: 669, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 19, track2Day: 69, category: "Childhood Patterns", question: "Type 3 children often report feeling like:", options: [{ letter: "A", text: "The odd one out who never fit in" }, { letter: "B", text: "A performer on stage, always being watched and evaluated" }, { letter: "C", text: "The caretaker who held the family together" }, { letter: "D", text: "An invisible child no one noticed" }], answer: "B", explanation: "Young Threes develop an awareness of being observed and judged. This sense of performing under evaluation becomes internalized, creating the lifelong feeling that they're always on stage." },
  { id: 670, type: 3, difficulty: 1 as 1|2|3|4|5, track1Day: 20, track2Day: 70, category: "Communication Style", question: "A Type 3's email style typically features:", options: [{ letter: "A", text: "Long, warm, personal messages" }, { letter: "B", text: "Concise bullet points with clear action items and polished professional tone" }, { letter: "C", text: "Stream-of-consciousness paragraphs" }, { letter: "D", text: "Delayed responses sent weeks later" }], answer: "B", explanation: "Threes communicate like they work: efficiently, professionally, and always image-conscious. Their emails are crafted to project competence and drive results, no wasted words, no vulnerability." },
  // ── DIFFICULTY 2 (20 questions) ──
  { id: 671, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 21, track2Day: 71, category: "Relationship Dynamics", question: "In romantic relationships, Type 3s are most at risk of:", options: [{ letter: "A", text: "Being too emotionally available and clingy" }, { letter: "B", text: "Treating the relationship like a project with KPIs, optimizing their partner and the relationship instead of feeling it" }, { letter: "C", text: "Being too passive and accommodating" }, { letter: "D", text: "Overthinking every interaction" }], answer: "B", explanation: "Threes can unconsciously apply their achievement framework to love: 'Am I in the best relationship? Is my partner impressive enough? Are we hitting our milestones?' This optimization replaces genuine emotional presence." },
  { id: 672, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 22, track2Day: 72, category: "Relationship Dynamics", question: "Why do Type 3s and Type 4s often have a complicated attraction?", options: [{ letter: "A", text: "They have nothing in common" }, { letter: "B", text: "The Four sees through the Three's image to their hidden depth, while the Three is drawn to the Four's authenticity they secretly crave" }, { letter: "C", text: "They both love social status" }, { letter: "D", text: "Their values are perfectly aligned" }], answer: "B", explanation: "The 3-4 pairing is a mirror of lack: the Three wants to feel authentic (like the Four), and the Four wants to feel successful (like the Three). Each has what the other fears they're missing." },
  { id: 673, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 23, track2Day: 73, category: "Defense Mechanisms", question: "What is the primary defense mechanism of Type 3?", options: [{ letter: "A", text: "Repression" }, { letter: "B", text: "Identification, merging their identity with their role, image, or achievements" }, { letter: "C", text: "Projection" }, { letter: "D", text: "Rationalization" }], answer: "B", explanation: "Identification means Threes become their persona. The mask fuses with the face. They don't just play the role of 'successful person', they genuinely believe they ARE the role, losing access to the person underneath." },
  { id: 674, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 24, track2Day: 74, category: "Defense Mechanisms", question: "How does the Three's 'deceit' passion actually operate day-to-day?", options: [{ letter: "A", text: "They consciously lie to manipulate others" }, { letter: "B", text: "They unconsciously deceive themselves about their true feelings by over-identifying with their image" }, { letter: "C", text: "They create elaborate cover stories" }, { letter: "D", text: "They're compulsive liars about everything" }], answer: "B", explanation: "Three's deceit is primarily self-deception, not con artistry. They genuinely don't know they're performing because the performance has become automatic. They've deceived themselves first, losing access to their real feelings." },
  { id: 675, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 25, track2Day: 75, category: "Conflict Style", question: "How do Type 3s typically handle conflict in professional settings?", options: [{ letter: "A", text: "They avoid it entirely" }, { letter: "B", text: "They strategically manage it to protect their image and position, often winning through competence rather than confrontation" }, { letter: "C", text: "They become aggressive and domineering" }, { letter: "D", text: "They defer to authority" }], answer: "B", explanation: "Threes in conflict think strategically, not emotionally. They manage disputes to protect their reputation, often winning by being more prepared, more polished, and more politically savvy than their opponent." },
  { id: 676, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 26, track2Day: 76, category: "Conflict Style", question: "When a Type 3's competence is publicly questioned, they:", options: [{ letter: "A", text: "Calmly accept the critique" }, { letter: "B", text: "Experience it as a threat to their core identity and respond with a polished counter-performance proving their worth" }, { letter: "C", text: "Collapse into self-doubt" }, { letter: "D", text: "Ignore it completely" }], answer: "B", explanation: "Questioning a Three's competence strikes at their foundation. They don't just defend themselves, they launch a performance proving how wrong the critic is, turning the challenge into another opportunity to shine." },
  { id: 677, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 27, track2Day: 77, category: "Shadow Work", question: "What is the Three's deepest fear that drives their achievement?", options: [{ letter: "A", text: "Being alone" }, { letter: "B", text: "Being worthless without their accomplishments, that underneath the achievements, there's nobody home" }, { letter: "C", text: "Being morally corrupt" }, { letter: "D", text: "Being physically harmed" }], answer: "B", explanation: "The Three's existential terror is emptiness. Strip away the titles, achievements, and image, and what's left? This fear of inner nothingness is what fuels the relentless drive to be someone through doing." },
  { id: 678, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 28, track2Day: 78, category: "Shadow Work", question: "The Three's 'golden child' syndrome refers to:", options: [{ letter: "A", text: "Being spoiled as a child" }, { letter: "B", text: "Being assigned the family role of representing success, making failure feel like betraying the family" }, { letter: "C", text: "Having naturally blonde hair" }, { letter: "D", text: "Being the favorite sibling without any consequences" }], answer: "B", explanation: "Many Threes were the family's trophy, the one whose achievements reflected well on the family. This creates enormous pressure: failure isn't just personal, it's letting down everyone who invested in your success." },
  { id: 679, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 29, track2Day: 79, category: "Parenting Style", question: "Type 3 parents are most likely to:", options: [{ letter: "A", text: "Let their children explore freely without structure" }, { letter: "B", text: "Enthusiastically celebrate their children's achievements while unconsciously pushing them toward impressive activities" }, { letter: "C", text: "Be emotionally demonstrative and affectionate above all" }, { letter: "D", text: "Focus primarily on moral education" }], answer: "B", explanation: "Three parents mean well but can unconsciously project their achievement orientation onto their children. They celebrate wins loudly and may sign kids up for every impressive activity, transferring their 'performance = love' equation." },
  { id: 680, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 30, track2Day: 80, category: "Attachment Style", question: "Which attachment style is most common among Type 3s?", options: [{ letter: "A", text: "Anxious-preoccupied" }, { letter: "B", text: "Dismissive-avoidant, they've learned to not need others' emotional support by being self-sufficient through achievement" }, { letter: "C", text: "Secure attachment" }, { letter: "D", text: "Fearful-avoidant" }], answer: "B", explanation: "Threes often develop dismissive-avoidant patterns because depending on others feels like weakness. Their self-sufficiency through achievement becomes a substitute for genuine emotional connection." },
  { id: 681, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 31, track2Day: 81, category: "Somatic Patterns", question: "Where do Type 3s most commonly hold stress in their body?", options: [{ letter: "A", text: "Their stomach and gut" }, { letter: "B", text: "Their heart center, chest tightness, shallow breathing, and a feeling of running on empty" }, { letter: "C", text: "Their head and forehead" }, { letter: "D", text: "Their lower back" }], answer: "B", explanation: "As a Heart center type, Threes' stress manifests in the chest. They often describe a tightness or emptiness in their heart area, shallow breathing from always being 'on,' and a deep fatigue hidden beneath their energetic exterior." },
  { id: 682, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 32, track2Day: 82, category: "Somatic Patterns", question: "Type 3s in burnout often experience:", options: [{ letter: "A", text: "Explosive anger outbursts" }, { letter: "B", text: "A sudden inability to perform, often accompanied by mysterious physical symptoms their body produces to force them to stop" }, { letter: "C", text: "Withdrawal into fantasy" }, { letter: "D", text: "Increased social activity" }], answer: "B", explanation: "When Threes override their body's signals for too long, the body forces a shutdown. Mysterious illnesses, chronic fatigue, or performance crashes serve as the body's veto when the mind won't stop." },
  { id: 683, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 33, track2Day: 83, category: "Coping Under Stress", question: "When stressed, Type 3s move toward which type's behaviors?", options: [{ letter: "A", text: "Type 6, becoming anxious, suspicious, and seeking security" }, { letter: "B", text: "Type 9, becoming apathetic, disengaged, and numbing out" }, { letter: "C", text: "Type 1, becoming rigid and critical" }, { letter: "D", text: "Type 8, becoming aggressive and controlling" }], answer: "B", explanation: "Under stress, Threes disintegrate to Nine: the go-getter becomes a couch potato. They numb out, binge-watch TV, overeat, and disengage from goals. It's the body's forced vacation from the relentless performance." },
  { id: 684, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 34, track2Day: 84, category: "Coping Under Stress", question: "What does healthy growth look like for a Type 3?", options: [{ letter: "A", text: "Achieving even more impressive goals" }, { letter: "B", text: "Moving toward Type 6 qualities: becoming loyal, collaborative, and honest about their vulnerabilities" }, { letter: "C", text: "Becoming more independent and detached" }, { letter: "D", text: "Focusing entirely on self-care" }], answer: "B", explanation: "In growth, Threes integrate to Six: they become team-oriented instead of solo achievers, honest about their fears instead of performing confidence, and loyal to relationships instead of networking for advantage." },
  { id: 685, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 35, track2Day: 85, category: "Workplace Archetypes", question: "Which workplace role does a Type 3 most naturally gravitate toward?", options: [{ letter: "A", text: "The behind-the-scenes technical expert" }, { letter: "B", text: "The visible high-performer who champions initiatives and drives results" }, { letter: "C", text: "The team mediator who resolves conflicts" }, { letter: "D", text: "The detail-oriented quality assurer" }], answer: "B", explanation: "Threes are drawn to visible, results-oriented roles where performance is measurable. They want to be seen succeeding, the salesperson of the year, the project lead, the one whose name is on the big wins." },
  { id: 686, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 36, track2Day: 86, category: "Workplace Archetypes", question: "A Type 3's biggest workplace blind spot is:", options: [{ letter: "A", text: "Lack of ambition" }, { letter: "B", text: "Taking shortcuts on ethical or relational dimensions because results are all that matter" }, { letter: "C", text: "Being too collaborative" }, { letter: "D", text: "Moving too slowly" }], answer: "B", explanation: "Threes can cut corners on relationships, ethics, or quality when the end result is all that matters. They may not realize they've left a trail of burned colleagues in their sprint to the finish line." },
  { id: 687, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 37, track2Day: 87, category: "Relationship Dynamics", question: "What makes Type 3s difficult to truly know in friendships?", options: [{ letter: "A", text: "They're introverted" }, { letter: "B", text: "They present a polished version of themselves and may not even know which version is real" }, { letter: "C", text: "They don't enjoy socializing" }, { letter: "D", text: "They're too blunt and honest" }], answer: "B", explanation: "Friends of Threes often sense they're getting a curated version. The Three isn't being dishonest, they genuinely may not know who they are beneath the persona, making true intimacy feel elusive." },
  { id: 688, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 38, track2Day: 88, category: "Conflict Style", question: "When receiving feedback, a Type 3 typically:", options: [{ letter: "A", text: "Becomes deeply emotional" }, { letter: "B", text: "Outwardly receives it graciously while internally strategizing how to never receive that criticism again" }, { letter: "C", text: "Argues every point defensively" }, { letter: "D", text: "Ignores it entirely" }], answer: "B", explanation: "Threes are masters of the graceful response to feedback. But inside, they're immediately strategizing: 'How do I fix this perception? How do I ensure no one ever says this about me again?'" },
  { id: 689, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 39, track2Day: 89, category: "Shadow Work", question: "Ichazo named the Three's fixation 'vanity' and the passion 'deceit.' What does vanity as a fixation (not the passion) actually mean for Threes?", options: [{ letter: "A", text: "They spend too much time looking in the mirror" }, { letter: "B", text: "The cognitive habit of constructing an idealized self-image and believing it to be real — a confusion between persona and essence that runs below conscious awareness" }, { letter: "C", text: "They're vain about physical appearance only" }, { letter: "D", text: "They brag constantly" }], answer: "B", explanation: "In Ichazo's framework, vanity is the Three's fixation (cognitive pattern), not the passion. The passion is deceit — the emotional drive to perform and be seen as successful. Vanity as fixation means the Three's mind automatically constructs an idealized self-image and mistakes it for reality, not mere conceit but a structural substitution of persona for essence." },
  { id: 690, type: 3, difficulty: 2 as 1|2|3|4|5, track1Day: 40, track2Day: 90, category: "Childhood Patterns", question: "How does the Three's childhood wound of 'conditional love' differ from the One's?", options: [{ letter: "A", text: "They're identical" }, { letter: "B", text: "Ones learned love came through being good; Threes learned love came through being impressive, performance, not morality, was the currency" }, { letter: "C", text: "Threes didn't experience conditional love" }, { letter: "D", text: "Ones performed; Threes were moral" }], answer: "B", explanation: "Both types learned love was conditional, but the currency differed. Ones earned love through virtue and correctness; Threes through achievement and admirability. This creates different adult strategies for the same core wound." },
  // ── DIFFICULTY 3 (20 questions) ──
  { id: 691, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 41, track2Day: 91, category: "Spiritual Traditions", question: "In contemplative traditions, the Three's growth path often involves:", options: [{ letter: "A", text: "More disciplined practice" }, { letter: "B", text: "Practices of 'being' without doing, learning to sit with emptiness and discover their intrinsic worth" }, { letter: "C", text: "Intellectual study of theology" }, { letter: "D", text: "Community service" }], answer: "B", explanation: "Threes need practices that interrupt doing. Meditation, silence, and sabbath teach them that they are valuable simply for existing, the hardest lesson for a type that equates worth with output." },
  { id: 692, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 42, track2Day: 92, category: "Spiritual Traditions", question: "The Christian concept of 'kenosis' (self-emptying) relates to the Three's journey because:", options: [{ letter: "A", text: "It doesn't apply" }, { letter: "B", text: "It describes the process of surrendering the inflated self-image to discover the true self beneath" }, { letter: "C", text: "It means physical fasting" }, { letter: "D", text: "It's about giving money to charity" }], answer: "B", explanation: "Kenosis, the emptying of ego, directly addresses the Three's core issue. Letting go of the image, the titles, the achievements, and the persona to discover what remains is the Three's essential spiritual task." },
  { id: 693, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 43, track2Day: 93, category: "Enneagram x MBTI", question: "How does a Type 3 ENTJ differ from a Type 3 ESFP?", options: [{ letter: "A", text: "They're identical" }, { letter: "B", text: "The ENTJ Three achieves through strategic vision and systems; the ESFP Three achieves through charisma, performance, and social impact" }, { letter: "C", text: "Only ENTJs can be Threes" }, { letter: "D", text: "The ESFP Three is more ambitious" }], answer: "B", explanation: "Same core motivation (achievement), different vehicles. ENTJ Threes build empires through strategy and leadership. ESFP Threes shine through personal magnetism, entertainment, or social influence. Both chase success, in different arenas." },
  { id: 694, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 44, track2Day: 94, category: "Enneagram x MBTI", question: "Which MBTI-Enneagram combination creates the 'workaholic' stereotype?", options: [{ letter: "A", text: "Type 3 ESTJ" }, { letter: "B", text: "Type 5 INTP" }, { letter: "C", text: "Type 9 ISFP" }, { letter: "D", text: "Type 7 ENFP" }], answer: "A", explanation: "The 3-ESTJ combination creates someone who is achievement-driven (Three) with a strong preference for structure, efficiency, and tangible results (ESTJ). They're the most likely to build their entire identity around their career." },
  { id: 695, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 45, track2Day: 95, category: "Instinct x Wing Combos", question: "How does a Self-Preservation 3 (SP3) differ from the stereotypical Three?", options: [{ letter: "A", text: "They're identical to the stereotype" }, { letter: "B", text: "SP3s are the counter-type, they achieve quietly and are modest about success, making them the hardest Threes to identify" }, { letter: "C", text: "SP3s are the most flamboyant" }, { letter: "D", text: "SP3s don't care about achievement" }], answer: "B", explanation: "SP3 is the counter-type Three who achieves without advertising it. They work extremely hard but avoid bragging, seeking security through competence rather than image. They often mistype as Ones or Sixes because they lack the flashy Three persona." },
  { id: 696, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 46, track2Day: 96, category: "Instinct x Wing Combos", question: "A Sexual (SX) Three is characterized by:", options: [{ letter: "A", text: "Focusing on career achievements above all else" }, { letter: "B", text: "Achieving through personal attractiveness and desirability, they want to be the most appealing person in the room" }, { letter: "C", text: "Being withdrawn and private" }, { letter: "D", text: "Focusing on group contributions" }], answer: "B", explanation: "SX Threes achieve through personal magnetism rather than career success. Their 'trophy' is being desirable, the most attractive, charming, or sexually compelling person. They promote their image through personal appeal, not just professional accomplishments." },
  { id: 697, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 47, track2Day: 97, category: "Tritype Deep Dives", question: "The 369 tritype ('The Chameleon') is notable because:", options: [{ letter: "A", text: "It contains three random types" }, { letter: "B", text: "It combines all three 'attachment' types, making this person extremely adaptable but potentially the most disconnected from their authentic self" }, { letter: "C", text: "It's the rarest tritype" }, { letter: "D", text: "It's the most aggressive tritype" }], answer: "B", explanation: "The 369 tritype contains the 'primary' type of each center (the type most adapted to social norms). These individuals are supremely adaptable, they can read and become what any situation requires, but may have the hardest time finding their real identity." },
  { id: 698, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 48, track2Day: 98, category: "Tritype Deep Dives", question: "How does a 358 tritype ('The Solution Master') approach problems?", options: [{ letter: "A", text: "With emotional sensitivity" }, { letter: "B", text: "With a combination of strategic efficiency (3), analytical depth (5), and forceful execution (8)" }, { letter: "C", text: "By avoiding them entirely" }, { letter: "D", text: "By seeking group consensus" }], answer: "B", explanation: "The 358 combines the Three's drive for results with the Five's analytical precision and the Eight's forceful action. This creates a formidable problem-solver who strategizes, analyzes, and then bulldozes through obstacles." },
  { id: 699, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 49, track2Day: 99, category: "Growth Practices", question: "Why is journaling about feelings (not accomplishments) particularly challenging and important for Type 3s?", options: [{ letter: "A", text: "They don't enjoy writing" }, { letter: "B", text: "It forces them to confront what they actually feel rather than what they've done, disconnecting the 'being' from the 'doing'" }, { letter: "C", text: "They find it boring" }, { letter: "D", text: "They already journal too much" }], answer: "B", explanation: "When Threes journal, they default to listing accomplishments. Journaling about feelings, 'How am I really doing?' not 'What did I accomplish?', forces them into unfamiliar emotional territory where their image can't protect them." },
  { id: 700, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 50, track2Day: 100, category: "Growth Practices", question: "The practice of 'failing on purpose' benefits Threes because:", options: [{ letter: "A", text: "It builds physical toughness" }, { letter: "B", text: "It reveals that their worth survives failure, loosening the grip of performance-based identity" }, { letter: "C", text: "It makes them more competitive" }, { letter: "D", text: "It doesn't benefit them at all" }], answer: "B", explanation: "Intentional small failures, telling an imperfect story, submitting a B-minus effort, admitting 'I don't know', teach Threes that they're still lovable without their best performance. The world doesn't collapse, and neither do they." },
  { id: 701, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Naranjo's Character Types", question: "Claudio Naranjo described the Three's character as:", options: [{ letter: "A", text: "The Perfectionist" }, { letter: "B", text: "The 'marketing orientation', someone who packages and sells themselves, becoming whatever the market demands" }, { letter: "C", text: "The Investigator" }, { letter: "D", text: "The Loyalist" }], answer: "B", explanation: "Naranjo, drawing on Erich Fromm's 'marketing personality,' described Threes as people who market themselves, they become products shaped by demand. Their authentic self is replaced by a self-as-brand." },
  { id: 702, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Naranjo's Character Types", question: "In Naranjo's framework, the Three's vanity is linked to:", options: [{ letter: "A", text: "Physical beauty" }, { letter: "B", text: "The inflated self-image that serves as a substitute for actual self-knowledge" }, { letter: "C", text: "Expensive possessions" }, { letter: "D", text: "Academic credentials" }], answer: "B", explanation: "Naranjo saw the Three's vanity not as mere conceit but as a structural feature: the inflated image IS the self they know. Without it, they face the terrifying void of not knowing who they actually are." },
  { id: 703, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Panel Wisdom", question: "In Enneagram panels, Type 3s commonly report:", options: [{ letter: "A", text: "Knowing exactly who they are from a young age" }, { letter: "B", text: "A moment of crisis where they realized they'd been performing their entire life and had no idea who they really were" }, { letter: "C", text: "Never caring about others' opinions" }, { letter: "D", text: "Preferring to work alone always" }], answer: "B", explanation: "The 'identity crisis' moment is a common Three panel theme: a midlife breakdown, burnout, or loss that forces them to confront the question they've been avoiding, 'Who am I without my achievements?'" },
  { id: 704, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Panel Wisdom", question: "Threes on panels often describe their relationship with emotions as:", options: [{ letter: "A", text: "Intensely emotional at all times" }, { letter: "B", text: "A delayed reaction, they feel emotions hours or days after the event, once the 'performing' stops" }, { letter: "C", text: "Emotionally numb always" }, { letter: "D", text: "Controlled anger" }], answer: "B", explanation: "Threes often describe emotional time-lag: they're 'fine' during a crisis, then break down days later in the shower. The performing self handles events in real-time; the feeling self catches up when the stage lights go off." },
  { id: 705, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Differential Diagnosis", question: "How do you distinguish a Type 3 from a Type 1?", options: [{ letter: "A", text: "You can't, they're the same type" }, { letter: "B", text: "Ones pursue excellence based on internal standards of rightness; Threes pursue excellence based on external markers of success and recognition" }, { letter: "C", text: "Ones are lazier than Threes" }, { letter: "D", text: "Threes care more about morality" }], answer: "B", explanation: "Both types are high-achievers, but the motivation differs. A One rewrites an email because it's not correct enough. A Three rewrites it because it doesn't position them impressively enough. Internal standard vs. external image." },
  { id: 706, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Differential Diagnosis", question: "How do you tell apart a Type 3 and a Type 7?", options: [{ letter: "A", text: "Sevens are more successful" }, { letter: "B", text: "Threes are driven by image and achievement; Sevens are driven by stimulation and avoiding pain, a Three works 80 hours to impress, a Seven starts 5 businesses because each one is exciting" }, { letter: "C", text: "They're identical types" }, { letter: "D", text: "Threes are more fun-loving" }], answer: "B", explanation: "Both types can be energetic and successful, but for different reasons. Threes endure suffering for results (delayed gratification); Sevens hop between opportunities because the novelty excites them (instant gratification)." },
  { id: 707, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Workplace Archetypes", question: "A Three with a 4-wing (3w4) in the workplace tends to:", options: [{ letter: "A", text: "Be indistinguishable from a pure Three" }, { letter: "B", text: "Combine achievement drive with aesthetic sensibility, they want to succeed AND create something with personal meaning" }, { letter: "C", text: "Avoid all creative work" }, { letter: "D", text: "Be purely analytical" }], answer: "B", explanation: "The 3w4 adds depth and creativity to the Three's achievement drive. They're drawn to careers where success includes artistic expression: film, fashion, architecture, or branding. They want to be admired for something unique, not just efficient." },
  { id: 708, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Workplace Archetypes", question: "A Three with a 2-wing (3w2) in the workplace tends to:", options: [{ letter: "A", text: "Work alone and avoid people" }, { letter: "B", text: "Achieve through people, charming, networking, leading teams, and being the charismatic motivator who inspires others" }, { letter: "C", text: "Focus only on data and analysis" }, { letter: "D", text: "Avoid leadership roles" }], answer: "B", explanation: "The 3w2 is the 'star performer' who achieves through interpersonal magnetism. They're natural politicians, salespeople, and leaders who combine the Three's drive with the Two's people-skills and desire to be loved." },
  { id: 709, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Somatic Patterns", question: "Type 3s often describe their relationship with their body as:", options: [{ letter: "A", text: "Deeply intuitive and connected" }, { letter: "B", text: "Instrumental, the body is a vehicle for performance, valued for what it can do and how it looks rather than how it feels" }, { letter: "C", text: "Completely disconnected" }, { letter: "D", text: "A source of constant pain" }], answer: "B", explanation: "Threes relate to their bodies the way they relate to everything: as a tool for achieving results. They push through exhaustion, illness, and pain signals because the body is a performance vehicle, not a felt experience." },
  { id: 710, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Coping Under Stress", question: "The Three's 'crash and burn' pattern typically follows this sequence:", options: [{ letter: "A", text: "Gradual slowdown and recovery" }, { letter: "B", text: "Overdrive → ignore warning signs → sudden collapse → period of numbness (Nine disintegration) → frantic return to performance" }, { letter: "C", text: "Steady decline over years" }, { letter: "D", text: "Explosive anger then quick recovery" }], answer: "B", explanation: "Threes don't burn out gradually, they sprint until they collapse. The pattern is predictable: push through every warning, crash spectacularly, zone out in Nine-ish numbness, then desperately resume performing as soon as possible." },
  // ── DIFFICULTY 4 (20 questions) ──
  { id: 711, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 41, track2Day: 91, category: "Ichazo Fixations", question: "Oscar Ichazo named the Three's fixation 'vanity.' In his framework, this means:", options: [{ letter: "A", text: "Excessive pride in appearance" }, { letter: "B", text: "The cognitive habit of constructing a false self-image and believing it is real, a fundamental confusion between persona and essence" }, { letter: "C", text: "Spending money on luxury items" }, { letter: "D", text: "Talking about oneself too much" }], answer: "B", explanation: "Ichazo's vanity is an epistemological problem: the Three literally cannot distinguish between their constructed image and their true self. The persona has replaced essence so completely that there's no separate observer to notice the substitution." },
  { id: 712, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 42, track2Day: 92, category: "Ichazo Fixations", question: "The Three's holy idea in Ichazo's system is 'Holy Law' or 'Holy Hope.' This means:", options: [{ letter: "A", text: "They should follow more rules" }, { letter: "B", text: "The recognition that each being has intrinsic value and a natural unfolding, achievement is not needed to justify existence" }, { letter: "C", text: "They should be more optimistic" }, { letter: "D", text: "The law of karma" }], answer: "B", explanation: "Holy Law teaches Threes that the universe has an inherent order where each being has value simply by existing. Achievement doesn't create worth, worth is a birthright. This directly dissolves the Three's performance-based identity." },
  { id: 713, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 43, track2Day: 93, category: "Object Relations Deep", question: "In object relations theory, the Three's developmental challenge relates to:", options: [{ letter: "A", text: "Trust vs. mistrust" }, { letter: "B", text: "The 'false self', developing a compliant persona to secure attachment while the authentic self goes underground" }, { letter: "C", text: "Separation anxiety" }, { letter: "D", text: "Oral fixation" }], answer: "B", explanation: "Winnicott's 'false self' concept maps directly to the Three. The child develops a performing self to maintain the caregiving bond, while the authentic self, with its messy needs and feelings, is suppressed as too risky to reveal." },
  { id: 714, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 44, track2Day: 94, category: "Object Relations Deep", question: "The Three's relationship to the 'mirroring' function in early development means:", options: [{ letter: "A", text: "They like looking in mirrors" }, { letter: "B", text: "They needed the parent to mirror their BEING, but instead got mirrored for their DOING, creating a self organized around accomplishment rather than identity" }, { letter: "C", text: "They mirror other people's behavior" }, { letter: "D", text: "They avoid mirrors" }], answer: "B", explanation: "In Kohut's framework, children need parents to mirror who they ARE. When parents only mirror achievements ('Great job!') without mirroring being ('I love watching you play'), the child builds an identity around performance rather than existence." },
  { id: 715, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 45, track2Day: 95, category: "Counter-Instinctual Combos", question: "Why is the Social Three (SO3) considered the most 'prototypical' Three?", options: [{ letter: "A", text: "Random convention" }, { letter: "B", text: "The social instinct amplifies the Three's image-consciousness, they perform for group recognition, making them the most visible and recognizable Threes" }, { letter: "C", text: "They're the most common" }, { letter: "D", text: "They score highest on tests" }], answer: "B", explanation: "SO3 aligns perfectly with the Three archetype: they achieve for social recognition, status, and group admiration. Their image-crafting is aimed at an audience, making them the polished, charismatic Threes that Enneagram books describe." },
  { id: 716, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 46, track2Day: 96, category: "Counter-Instinctual Combos", question: "The SP3 is considered counter-instinctual because:", options: [{ letter: "A", text: "They dislike money" }, { letter: "B", text: "Their self-preservation instinct creates a Three who achieves but downplays it, they're efficient and hardworking but modest, making 'vanity' look like its opposite" }, { letter: "C", text: "They're lazy" }, { letter: "D", text: "They're antisocial" }], answer: "B", explanation: "SP3s are vain about NOT being vain. Their counter-instinctual nature means they achieve intensely but present as humble and practical. The vanity is hidden in their self-image as someone who doesn't need recognition, which is itself a form of image management." },
  { id: 717, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 47, track2Day: 97, category: "Historical Enneagram", question: "In the Sufi tradition that influenced Enneagram development, the Three's challenge relates to:", options: [{ letter: "A", text: "Physical asceticism" }, { letter: "B", text: "The concept of 'nafs' (ego-self), the Three is trapped in the most socially reinforced form of ego, making awakening particularly difficult" }, { letter: "C", text: "Memorizing scripture" }, { letter: "D", text: "Ritual prayer" }], answer: "B", explanation: "The Sufi insight is that the Three's ego is the hardest to see because society rewards it. Culture celebrates achievement, image, and success, all Three fixations. Swimming against this current makes the Three's spiritual journey uniquely challenging." },
  { id: 718, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 48, track2Day: 98, category: "Historical Enneagram", question: "Gurdjieff's concept of 'false personality' most directly relates to which Enneagram type?", options: [{ letter: "A", text: "Type 5" }, { letter: "B", text: "Type 3, the false personality that believes it is the real person" }, { letter: "C", text: "Type 8" }, { letter: "D", text: "Type 1" }], answer: "B", explanation: "Gurdjieff taught that most people are asleep, identified with a false personality they mistake for their real self. While this applies to all types, the Three embodies this concept most precisely, their entire structure IS the false personality." },
  { id: 719, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 49, track2Day: 99, category: "Integration/Disintegration Chains", question: "When a Three disintegrates to Nine, then that Nine-like state further degrades, what does it look like?", options: [{ letter: "A", text: "Explosive anger" }, { letter: "B", text: "Complete shutdown, not just low productivity but a narcotized numbness where they can't remember what they even want, accompanied by stubborn resistance to others' attempts to motivate them" }, { letter: "C", text: "Manic energy" }, { letter: "D", text: "Obsessive worry" }], answer: "B", explanation: "Deep Three disintegration looks like severe Nine: total disengagement, emotional flatness, binge-watching or overeating as numbing agents, and paradoxically stubborn resistance to the very achievement that usually defines them." },
  { id: 720, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 50, track2Day: 100, category: "Integration/Disintegration Chains", question: "When a Three integrates to Six and then continues growing, they develop:", options: [{ letter: "A", text: "More ambition" }, { letter: "B", text: "True courage, the ability to be vulnerable, loyal, and honest about their limitations without it feeling like brand damage" }, { letter: "C", text: "Increased independence" }, { letter: "D", text: "Spiritual detachment" }], answer: "B", explanation: "Advanced Three integration brings genuine courage: admitting weakness, staying loyal when it's not strategic, and being honest even when the truth hurts their image. They become leaders who inspire through authenticity rather than performance." },
  { id: 721, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Naranjo's Character Types", question: "Naranjo identified that Threes in therapy often present a unique challenge because:", options: [{ letter: "A", text: "They refuse to attend sessions" }, { letter: "B", text: "They perform being a 'good client', doing all the homework, saying insightful things, while the performing self prevents genuine therapeutic contact" }, { letter: "C", text: "They're too emotional" }, { letter: "D", text: "They don't understand the concepts" }], answer: "B", explanation: "Threes can win at therapy the way they win at everything: they become the star patient. The performance of growth substitutes for actual growth, and the therapist may not realize the Three is performing vulnerability rather than experiencing it." },
  { id: 722, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Differential Diagnosis", question: "A person is highly successful, driven, and admired. How do you distinguish whether they're a Three or an Eight?", options: [{ letter: "A", text: "Check their net worth" }, { letter: "B", text: "Threes seek admiration and adjust their image to earn it; Eights seek impact and don't care if people admire them, they'd rather be respected or feared than liked" }, { letter: "C", text: "Eights work harder" }, { letter: "D", text: "There's no difference" }], answer: "B", explanation: "Both types achieve, but for different reasons. Threes need the world to see them as successful (image-driven). Eights need to impact the world on their terms (power-driven). An Eight will sacrifice their image for control; a Three will sacrifice control for image." },
  { id: 723, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Differential Diagnosis", question: "A high-performing person says 'I need people to see what I've accomplished.' This could be a 3 or a 2. How do you tell?", options: [{ letter: "A", text: "Only Threes say this" }, { letter: "B", text: "The Three wants admiration for competence and success; the Two wants appreciation for their sacrifices and helpfulness, same desire for recognition, different currencies" }, { letter: "C", text: "Only Twos say this" }, { letter: "D", text: "Neither type would say this" }], answer: "B", explanation: "Both types crave recognition, but what they want recognized differs. Threes want: 'Look how impressive I am.' Twos want: 'Look how much I've given.' The Three's currency is achievement; the Two's is sacrifice." },
  { id: 724, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Shadow Work", question: "The Three's relationship with shame is unique because:", options: [{ letter: "A", text: "They don't experience shame" }, { letter: "B", text: "As a Heart center type, shame is their core emotion, but they're the most disconnected from it, burying it under achievement rather than feeling it like Twos and Fours" }, { letter: "C", text: "They shame others constantly" }, { letter: "D", text: "They openly discuss their shame" }], answer: "B", explanation: "All Heart types (2, 3, 4) deal with shame, but each differently. Twos outrun shame through giving, Fours marinate in it. Threes are most disconnected, they've built an entire identity system to ensure shame never surfaces. When it does, it's devastating." },
  { id: 725, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Growth Practices", question: "Why is 'telling someone what you actually feel before you've processed it into a polished narrative' a radical act for Threes?", options: [{ letter: "A", text: "They're naturally articulate" }, { letter: "B", text: "It bypasses their image-management system, revealing the raw, unedited self they've spent their life hiding" }, { letter: "C", text: "It's not radical at all" }, { letter: "D", text: "They never have feelings to share" }], answer: "B", explanation: "Threes process emotions through their image filter: raw feeling goes in, polished narrative comes out. Speaking before the editing process completes means revealing the unpackaged, imperfect, real self, terrifying for a type built on presentation." },
  { id: 726, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Tritype Deep Dives", question: "In a 378 tritype ('The Mover Shaker'), the Three's achievement drive combines with:", options: [{ letter: "A", text: "Caution and withdrawal" }, { letter: "B", text: "Seven's visionary optimism and Eight's forcefulness, creating a powerhouse who dreams big, brands big, and executes with intensity" }, { letter: "C", text: "Self-doubt and anxiety" }, { letter: "D", text: "Emotional sensitivity and withdrawal" }], answer: "B", explanation: "The 378 is arguably the most driven tritype. Three provides the image consciousness, Seven adds the visionary scope and enthusiasm, and Eight supplies the willpower and fearlessness. Together: unstoppable ambition with powerful execution." },
  { id: 727, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Spiritual Traditions", question: "The Buddhist concept of 'emptiness' (sunyata) challenges the Three because:", options: [{ letter: "A", text: "They can't sit still in meditation" }, { letter: "B", text: "It directly confronts their deepest fear, that the self they've constructed has no inherent existence, and what remains when the image is stripped is not nothing but boundless potential" }, { letter: "C", text: "Buddhism discourages achievement" }, { letter: "D", text: "They don't understand philosophy" }], answer: "B", explanation: "Sunyata teaches that no fixed self exists, exactly what the Three fears most. But the Buddhist twist is liberating: emptiness isn't void, it's openness. Without a fixed persona, the Three can be anything authentically rather than performing one role." },
  { id: 728, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Attachment Style", question: "How does a Three's dismissive-avoidant attachment manifest differently from a Five's?", options: [{ letter: "A", text: "They're identical" }, { letter: "B", text: "Threes are avoidant but socially engaged, they surround themselves with people while remaining emotionally unreachable; Fives withdraw physically AND emotionally" }, { letter: "C", text: "Threes aren't avoidant" }, { letter: "D", text: "Fives are more social" }], answer: "B", explanation: "The Three's avoidance is paradoxical: they can be the life of the party yet emotionally unavailable. They have a wide social network but no one who truly knows them. Fives at least are honest about their withdrawal; Threes hide theirs behind charisma." },
  { id: 729, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Parenting Style", question: "The Three parent's greatest growth edge is learning to:", options: [{ letter: "A", text: "Push their kids harder" }, { letter: "B", text: "Celebrate their child's being rather than their doing, saying 'I love watching you play' rather than 'Great job winning!'" }, { letter: "C", text: "Be stricter" }, { letter: "D", text: "Spend more money on enrichment" }], answer: "B", explanation: "Three parents unconsciously pass on the performance = love equation. Their deepest growth comes from mirroring their child's existence rather than their achievements: 'I love who you are, not what you do.'" },
  { id: 730, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Communication Style", question: "In couples therapy, Threes often struggle with:", options: [{ letter: "A", text: "Talking too much about feelings" }, { letter: "B", text: "The requirement to be emotionally present without performing, the therapeutic space demands authentic vulnerability, which their system is designed to prevent" }, { letter: "C", text: "Following the therapist's instructions" }, { letter: "D", text: "Showing up on time" }], answer: "B", explanation: "Couples therapy asks Threes to do the one thing they're least equipped for: be real in real-time. They can perform vulnerability, but the partner usually senses the difference, and so does a skilled therapist." },
  // ── DIFFICULTY 5 (20 questions) ──
  { id: 731, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 41, track2Day: 91, category: "Ichazo Fixations", question: "Ichazo's concept of the Three's 'trap' is 'efficiency.' What does this mean?", options: [{ letter: "A", text: "Threes are good at time management" }, { letter: "B", text: "The Three believes that doing things efficiently will eventually lead to genuine fulfillment, but efficiency itself becomes the endless treadmill replacing the inner work they need" }, { letter: "C", text: "Efficiency is always positive" }, { letter: "D", text: "They should be less efficient" }], answer: "B", explanation: "The 'trap' in Ichazo's system is the strategy that seems like growth but actually reinforces the fixation. For Threes, getting more efficient at achieving feels like progress but just accelerates the hamster wheel, real growth requires stopping, not optimizing." },
  { id: 732, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 42, track2Day: 92, category: "Ichazo Fixations", question: "The Three's virtue in the Enneagram is 'Truthfulness' (or 'Veracity'). This means:", options: [{ letter: "A", text: "Not lying to others" }, { letter: "B", text: "The capacity to perceive and present themselves as they actually are, without image-management, a state where being and appearing are unified" }, { letter: "C", text: "Being bluntly honest" }, { letter: "D", text: "Telling people uncomfortable truths" }], answer: "B", explanation: "Veracity for the Three isn't about external honesty but internal alignment: the end of self-deception. When a Three achieves veracity, there's no gap between who they are and who they present, the persona dissolves into authenticity." },
  { id: 733, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 43, track2Day: 93, category: "Object Relations Deep", question: "The Three's relationship to D.W. Winnicott's 'true self/false self' theory is:", options: [{ letter: "A", text: "Unrelated" }, { letter: "B", text: "Directly central, the Three develops the most sophisticated false self to maintain attachment, while the true self goes so far underground that the Three may need years of therapy to even suspect it exists" }, { letter: "C", text: "Only the false self exists" }, { letter: "D", text: "Winnicott was describing only Fours" }], answer: "B", explanation: "Winnicott's false self concept was practically designed for Threes. Their compliant, performing self maintained the caregiving bond so effectively that the true self, spontaneous, messy, authentic, was buried. Recovery means slowly coaxing the true self back." },
  { id: 734, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 44, track2Day: 94, category: "Object Relations Deep", question: "How does the Three's narcissistic structure differ from clinical narcissistic personality disorder?", options: [{ letter: "A", text: "They're identical" }, { letter: "B", text: "Three's narcissism is ego-syntonic image maintenance, not necessarily involving exploitation, lack of empathy, or entitlement, healthy Threes can be deeply caring while still struggling with image-identity confusion" }, { letter: "C", text: "Threes are worse" }, { letter: "D", text: "There's no narcissism in Threes" }], answer: "B", explanation: "While Three and NPD share surface features (image-focus, achievement-drive), healthy Threes have genuine empathy and care. Their narcissistic structure is about identity confusion (who am I without my image?), not interpersonal exploitation." },
  { id: 735, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 45, track2Day: 95, category: "Counter-Instinctual Combos", question: "An SP3 with a 4-wing (SP 3w4) is arguably the hardest Three to type because:", options: [{ letter: "A", text: "They don't exist" }, { letter: "B", text: "They combine the counter-type's modesty with the 4-wing's emotional depth and sense of being different, they may look like a One, Four, Five, or Six before anyone considers Three" }, { letter: "C", text: "They look exactly like a stereotypical Three" }, { letter: "D", text: "They're always extroverted" }], answer: "B", explanation: "SP 3w4 layers three disguises: the SP counter-type hides the typical Three flash, the 4-wing adds introspection and melancholy, and together they create a hardworking, quietly intense person who doesn't match any Three stereotype. Master of hidden vanity." },
  { id: 736, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 46, track2Day: 96, category: "Counter-Instinctual Combos", question: "SX3 with a 2-wing (SX 3w2) can be confused with which type?", options: [{ letter: "A", text: "Type 5" }, { letter: "B", text: "Type 2, because the sexual instinct's desire for desirability combined with the 2-wing's interpersonal focus creates someone who appears to be a helper/pleaser but is actually image-managing for admiration" }, { letter: "C", text: "Type 9" }, { letter: "D", text: "Type 1" }], answer: "B", explanation: "SX 3w2 looks remarkably like a Two: warm, attentive, people-oriented, seemingly selfless. But the motivation differs, a Two gives to be needed, while this Three charms to be admired. The question is: 'Do I help to be loved, or do I charm to be desired?'" },
  { id: 737, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 47, track2Day: 97, category: "Historical Enneagram", question: "In Riso and Hudson's framework, the Three's 'Direction of Disintegration' at Level 7-9 manifests as:", options: [{ letter: "A", text: "Healthy behavior" }, { letter: "B", text: "Deceptive, jealous, and vindictive behavior, the Three becomes willing to sabotage others' success to protect their own image, crossing ethical lines they'd normally respect" }, { letter: "C", text: "Simple laziness" }, { letter: "D", text: "Increased generosity" }], answer: "B", explanation: "At unhealthy levels, Three disintegration includes Nine-ish numbness AND toxic competition: sabotaging rivals, fabricating credentials, and engaging in the very deception that healthy Threes work hard to avoid. The image must be protected at any cost." },
  { id: 738, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 48, track2Day: 98, category: "Historical Enneagram", question: "The Enneagram of Process positions the Three between Two and Four. What does this reveal about the Three's inner struggle?", options: [{ letter: "A", text: "Nothing meaningful" }, { letter: "B", text: "The Three is caught between the Two's strategy of gaining love through others and the Four's desire for authentic self-expression, they oscillate between pleasing and individuating" }, { letter: "C", text: "They should become a Two or Four" }, { letter: "D", text: "It's a random numbering system" }], answer: "B", explanation: "The Three's position between Two and Four reveals their core tension: wing toward Two and they gain love through others but lose themselves; wing toward Four and they individuate but risk the isolation of authenticity. Both wings pull toward opposing strategies." },
  { id: 739, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 49, track2Day: 99, category: "Integration/Disintegration Chains", question: "The Three → Six → Nine integration/disintegration chain reveals:", options: [{ letter: "A", text: "Random type connections" }, { letter: "B", text: "A journey from performance (3) through loyalty and vulnerability (6) to acceptance and presence (9), the Three must first learn to commit honestly, then to simply be" }, { letter: "C", text: "Numerical patterns" }, { letter: "D", text: "Only negative outcomes" }], answer: "B", explanation: "The 3-6-9 triangle maps the Three's growth trajectory: from performing for admiration (3) to committing genuinely to people and causes (6) to resting in present-moment acceptance without needing to produce (9). Each step requires releasing a layer of persona." },
  { id: 740, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 50, track2Day: 100, category: "Integration/Disintegration Chains", question: "The 3-6-9 triangle in the Enneagram is called the 'attachment' or 'primary' triangle because:", options: [{ letter: "A", text: "These types like to attach to objects" }, { letter: "B", text: "All three types adapted most directly to the social world, the Three to succeed in it, the Six to find security within it, the Nine to maintain peace in it, making their ego structures the most socially embedded" }, { letter: "C", text: "They're the three most popular types" }, { letter: "D", text: "They were discovered first" }], answer: "B", explanation: "The 3-6-9 triangle represents the three fundamental strategies for navigating the social world. All three types shaped themselves most completely around external demands, which is why they're called 'primary', their fixation is the most mainstream and hardest to see." },
  { id: 741, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Naranjo's Character Types", question: "Naranjo described the Three's emotional style as 'affect without feeling.' What does this mean?", options: [{ letter: "A", text: "They're robots" }, { letter: "B", text: "They can display the appearance of emotion (tears, warmth, enthusiasm) without actually experiencing the feeling underneath, the performance of emotion replaces felt emotion" }, { letter: "C", text: "They feel too much" }, { letter: "D", text: "They're stoic" }], answer: "B", explanation: "Naranjo noticed that Threes could produce emotional displays on command: tears in therapy, enthusiasm in meetings, warmth with friends, but the feeling underneath was often absent or thin. They'd learned to perform emotions so well they confused the performance with the real thing." },
  { id: 742, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Panel Wisdom", question: "Advanced Three panelists often describe their deepest moment of growth as:", options: [{ letter: "A", text: "Winning their biggest award" }, { letter: "B", text: "A moment when they were seen for who they really are, flawed, uncertain, not performing, and were loved anyway" }, { letter: "C", text: "Getting a major promotion" }, { letter: "D", text: "Beating a rival" }], answer: "B", explanation: "Threes who have done deep work consistently describe the same pivotal moment: being genuinely seen, without the mask, without the resume, without the performance, and discovering that love still showed up. This shatters the 'love requires achievement' belief." },
  { id: 743, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Differential Diagnosis", question: "An executive is strategic, hard-driving, and image-conscious. How do you distinguish a very healthy Eight from a Three?", options: [{ letter: "A", text: "Income level" }, { letter: "B", text: "Ask what they'd sacrifice. A Three would sacrifice authenticity to maintain admiration; an Eight would sacrifice admiration to maintain autonomy and truth, even at the cost of being disliked" }, { letter: "C", text: "Physical size" }, { letter: "D", text: "There's no way to distinguish them" }], answer: "B", explanation: "The acid test: 'What would you give up last?' Threes protect their image above all. Eights protect their autonomy above all. A Three who's disliked feels worthless; an Eight who's controlled feels trapped. Different core fears, different sacrificial hierarchies." },
  { id: 744, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Differential Diagnosis", question: "A successful but self-doubting person could be a 3 or a 6. The key differentiator is:", options: [{ letter: "A", text: "Self-doubt rules out Three" }, { letter: "B", text: "The Three's doubt is about their image ('Am I impressive enough?') while the Six's doubt is about their competence and the world's trustworthiness ('Am I safe? Can I trust this?')" }, { letter: "C", text: "Sixes are never successful" }, { letter: "D", text: "It's impossible to tell" }], answer: "B", explanation: "Both types can experience self-doubt, but about different things. Three-doubt: 'Do people admire me? Is my image holding up?' Six-doubt: 'Is this situation safe? Can I trust my own judgment?' Same emotion, different objects of fixation." },
  { id: 745, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Shadow Work", question: "The Three's 'shadow achievement' refers to:", options: [{ letter: "A", text: "Working at night" }, { letter: "B", text: "The hidden truth that much of their achievement was driven not by genuine desire but by fear of worthlessness, confronting this means grieving the years spent achieving things they didn't actually want" }, { letter: "C", text: "Achievements no one knows about" }, { letter: "D", text: "Cheating to win" }], answer: "B", explanation: "Deep Three work involves the devastating recognition that many trophies in their case were fear-driven, not desire-driven. Grieving the career they built to impress rather than to express is one of the Three's most painful and necessary passages." },
  { id: 746, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Growth Practices", question: "The practice of 'disappearing', taking anonymous vacations, volunteering without credit, or creating art without publishing it, benefits Threes because:", options: [{ letter: "A", text: "They need more vacation time" }, { letter: "B", text: "It separates the experience of living from the experience of being witnessed, revealing whether they can enjoy something that no one will ever applaud" }, { letter: "C", text: "It's trendy" }, { letter: "D", text: "It builds networking skills" }], answer: "B", explanation: "Can a Three enjoy a hike if they don't post about it? Create something beautiful without anyone knowing? This practice isolates the Three's most fundamental question: 'Is the joy in the doing, or in being seen doing?'" },
  { id: 747, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Tritype Deep Dives", question: "The 316 tritype creates a unique Three variant because:", options: [{ letter: "A", text: "It's contradictory" }, { letter: "B", text: "The One adds internal standards of integrity and the Six adds loyalty and doubt, creating a Three who achieves but genuinely cares about doing it right and staying loyal, making them the most trustworthy Three variant" }, { letter: "C", text: "It doesn't create anything unique" }, { letter: "D", text: "All tritypes are the same" }], answer: "B", explanation: "The 316 tritype tempers the Three's image-focus with the One's ethics and the Six's loyalty. This Three achieves within moral boundaries and stays committed to people beyond their strategic value, making them a Three you can actually trust." },
  { id: 748, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Spiritual Traditions", question: "The Three's spiritual journey parallels the mythological theme of:", options: [{ letter: "A", text: "The warrior's quest" }, { letter: "B", text: "The descent, like Inanna or Orpheus, the Three must go underground, losing everything that made them 'somebody,' to discover who they are at the core" }, { letter: "C", text: "The trickster" }, { letter: "D", text: "The creation myth" }], answer: "B", explanation: "The descent myth is the Three's map: going down, not up. Losing titles, status, approval, image, descending into the underworld of the psyche where achievements can't protect them, to find the gold of authentic selfhood in the darkness." },
  { id: 749, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Instinct x Wing Combos", question: "Rank the six Three subtypes (3 instincts × 2 wings) from most to least visibly 'Three-like':", options: [{ letter: "A", text: "All look the same" }, { letter: "B", text: "SO 3w2 (most visible) → SX 3w2 → SO 3w4 → SX 3w4 → SP 3w2 → SP 3w4 (least visible)" }, { letter: "C", text: "SP 3w4 is the most visible" }, { letter: "D", text: "The ranking can't be determined" }], answer: "B", explanation: "Visibility tracks with how much the subtype amplifies the Three archetype. SO + 2-wing = maximum charisma and social performance. SP + 4-wing = maximum counter-type hiding: efficient, humble, introspective, and nearly invisible as a Three." },
  { id: 750, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Panel Wisdom", question: "Experienced Enneagram teachers often say that 'America is a Three culture.' This means:", options: [{ letter: "A", text: "Most Americans are Threes" }, { letter: "B", text: "American culture rewards and normalizes Three values, success, image, achievement, optimism, self-promotion, making the Three fixation the hardest to see because the entire culture is an enabler" }, { letter: "C", text: "Threes founded America" }, { letter: "D", text: "American culture is the best" }], answer: "B", explanation: "The cultural observation is that American values (meritocracy, self-improvement, personal branding, optimism) perfectly align with Three fixations. This means Threes are swimming in a culture that validates their ego structure, making awakening from it extraordinarily difficult." },
];
